failure.message:
AssertionError: Expected 200/201, got 404: {"detail":"Customer not found"}
assert 404 in (200, 201)
 +  where 404 = <Response [404]>.status_code

AssertionError: Unexpected response: 422: {"detail":[{"type":"missing","loc":["body","name"],"msg":"Field required","input":{"is_active":false}}]}
